const payload = $input.first().json;
const message = payload.message || {};
const thread = payload.thread || {};

let fromField = message.from_ || message.from || '';
let senderEmail = fromField;
if (fromField.includes('<') && fromField.includes('>')) {
  senderEmail = fromField.split('<')[1].split('>')[0].trim();
} else {
  senderEmail = fromField.trim();
}

const body = message.extracted_text || message.text || message.extracted_html || message.html || message.preview || '';

if (!message.message_id || !message.inbox_id) {
  throw new Error('Missing message_id or inbox_id');
}
if (!body || body.trim().length === 0) {
  throw new Error('Empty email body');
}

return [{
  json: {
    event_id: payload.event_id || '',
    sender_email: senderEmail,
    raw_from: fromField,
    to: message.to || [],
    cc: message.cc || [],
    subject: message.subject || '(no subject)',
    body: body,
    message_id: message.message_id,
    inbox_id: message.inbox_id,
    thread_id: message.thread_id || thread.thread_id || '',
    existing_labels: message.labels || [],
    thread_labels: thread.labels || [],
    thread_message_count: thread.message_count || 1,
    has_attachments: (message.attachments || []).length > 0,
    attachment_count: (message.attachments || []).length,
    received_at: message.timestamp || message.created_at || new Date().toISOString(),
    processed_at: new Date().toISOString()
  }
}];

