// Build 4 lean labels + merge all data for downstream

const raw = $input.first().json;
const triage = raw.output || raw;
const labels = [];

// === 4 LABELS FOR AGENTMAIL ===
if (triage.sla_status) labels.push(`sla:${triage.sla_status}`);
if (triage.inquiry_category) labels.push(`pipeline:${triage.inquiry_category}`);
if (triage.stucco_priority) labels.push(`priority:${triage.stucco_priority}`);
if (triage.sentiment) labels.push(`sentiment:${triage.sentiment}`);

// === GET EMAIL DATA (loop-safe) ===
let emailData;
try {
  emailData = $('Extract Email Content').item.json;
} catch (e) {
  emailData = $('Extract Email Content').first().json;
}

return [{
  json: {
    labels: labels,
    message_id: emailData.message_id,
    inbox_id: emailData.inbox_id,
