// Grab new contact_id from create response

const items = $input.all();
const results = [];

for (const item of items) {
  const apiResponse = item.json;

  const contactId = apiResponse.id
    || apiResponse.data?.id
    || apiResponse.data?.[0]?.id
    || '';

  let triageData;
  try {
    triageData = $('Select CRM List for SLA').item.json;
  } catch (e) {
    triageData = $('Select CRM List for SLA').first().json;
  }

  results.push({
    json: {
      ...triageData,
      contact_id: contactId,
      contact_status: 'new'
    }
  });
}

return results;

// Final confirmation

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  results.push({
    json: {
      status: 'complete',
      summary: `${data.contact_status === 'new' ? '➕ Created' : '✅ Found'} contact → Added to ${data.sla_status} list`,
      contact_id: data.contact_id,
      contact_status: data.contact_status,
      sla_status: data.sla_status,
      sender_email: data.sender_email,
      subject: data.subject
    }
  });
}

return results;

// Map SLA status to NinjaPipe List ID

const items = $input.all();
const results = [];

const listMap = {
  'RED':    'REPLACE_WITH_RED_LIST_UUID',
  'ORANGE': 'REPLACE_WITH_ORANGE_LIST_UUID',
  'YELLOW': 'REPLACE_WITH_YELLOW_LIST_UUID',
  'GREEN':  'REPLACE_WITH_GREEN_LIST_UUID'
};

for (const item of items) {
  const data = item.json;

  let contactName = data.sender_email || 'Unknown';
  const rawFrom = data.raw_from || data.sender_email || '';
  if (rawFrom.includes('<')) {
    contactName = rawFrom.split('<')[0].trim() || contactName;
  }

  // Split name into first/last
  const nameParts = contactName.split(' ');
  const firstName = nameParts[0] || 'Unknown';
  const lastName = nameParts.slice(1).join(' ') || '';

  results.push({
    json: {
      ...data,
      target_list_id: listMap[data.sla_status] || listMap['GREEN'],
      search_email: data.sender_email,
      contact_name: contactName,
      contact_first_name: firstName,
      contact_last_name: lastName
    }
  });
}

return results;
